{
  "verses": [
    {
      "n": 6,
      "column": "left",
      "text": "Jo no Pihſchleem ta Ne-\ntaſjniba ne iſang/ un no Sem-\nmes tas Gruhtums ne iſplaukſt.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Bet tas Zilweks us Gruh-\ntumu peedſemin/ ka tahs Dſirk-\nſteles no Ohglehm pazeltahs\nſkraidibt.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Bet es to STIPRU\nDEEWU mekletu/ un paweh-\nletu Deewam fawas Leetas.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Kas leelas Leetas darra/\nkas ne irr iſwaizajamas/ un\nVrihnumus/ ko ne warr ſkaitibt.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Kas Leetus dohd wirs\nSemmes/ un leek Uhdeni nahkt\nus Eelahm.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Ka tas tohs Paſenumus\npa-augſtina/ ka tee Behdige\ntaur Beſtſchanu tohp uſzelti.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Wiꞥſch iſnihzina to Wilt-\nneeku Padohmu/ ka wirnu Roh-\ntas ne kahdu Leetu warr padar-\nriht.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Wiꞥſch fatwerx tohs Gund-\nrus eekſch winnu Wiltibas/ un\nto Gewaldſinataju Padohms\ntohp ahtri iſnihzinahts.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Zaur Deenu tee ſkraida\neekſch Tumſtbas/ un Deenas-\nWiddû tee grabbſta ka Nakti.\n"
    },
    {
      "n": 15,
      "column": "left",
      "text": "Bet wiꞥſch iſgiabbi to\nNabbagu no Sohbina/ un no\nwinnu Muttes/ un to Behdigu\nno ta Stipra Rohkas.\n"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Ta irr tam Rabbagam\nZerrba/ bet tat Blehdibat buhs\nfawu Mutti turreht.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Redſi/ ſwehtigs irr t\nZilweks/ ko Deews pawrmahz\ntapehz ne Reinn ta Wiſtuwar-\nna Pawrmahztichann par Laun\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Jo wiꞥſch eewaino un a\nkat aiſteen. Wiꞥſch tadauſe\nun winna Rohka dseedina.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Eekſch feſchahm Be-\ndahm wiꞥſch tewi iſglahbs/\nſeptitá tewi Launuuns ne a\nkahs.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Badda Laiká tspesti\nwiꞥſch tewi no Nahwes/un Ka-\nra Laiká no ta Sohbina Ra-\ntchanas.\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Preeſch Aprunnata\nUsmahſtchanas tapſi tu p\nſlehpts/ un tu ne bihſees preeſf\nIſpohſtſtchanas/ kad ta nahk.\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Pohſtſtchaná un Bad-\ntu ſimeefees/ un no teem Se-\nmes Swehreem ne bihſees.\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Jo tew buhs Derriba\nteem Atmiſeem Tibrumá/\ntee Swehri Lauká turrehs ar te\nMeeru.\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Un tu fajuttifi/ ka tat\nDſihwoklis ar Meeru buhs/ u\ntu apgahdafi tawu Namnn/ u\nne grehkoff.\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Ir tu fajuttifi/ ka tat\nDſimnuma dands buhs/ un t\nwee Pehznabkamee/ ka ta Sa-\nle wirs Semmes.\n"
    },
    {
      "n": 26,
      "column": "right",
      "text": "Tu nahkſt Wezzun\neekſch Kappa/ itt ka Labbtb\nGubbinas tohp eewestas fan-\nraſká.\n"
    },
    {
      "n": 27,
      "column": "right",
      "text": "Redſi/ ſcho: To eſa-\nmehs iſmeklejſchi/ tas irr t\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
